const t = input.trim();
// Extract operation type and name
const opMatch = t.match(/^\s*(query|mutation|subscription|fragment)\s*(\w*)\s*(\([^)]*\))?/i);
const opType = opMatch ? opMatch[1] : 'anonymous';
const opName = opMatch && opMatch[2] ? opMatch[2] : '(unnamed)';
const varBlock = opMatch && opMatch[3] ? opMatch[3] : null;

// Extract variables
const vars = [];
if (varBlock) {
  const varRe = /\$(\w+)\s*:\s*([\w!\[\]]+)/g;
  let vm;
  while ((vm = varRe.exec(varBlock)) !== null) {
    vars.push({ name: vm[1], type: vm[2] });
  }
}

// Count braces depth to estimate nesting
let depth = 0, maxDepth = 0;
for (const ch of t) {
  if (ch === '{') { depth++; maxDepth = Math.max(maxDepth, depth); }
  else if (ch === '}') depth--;
}

// Extract field names (simple heuristic: words before { or followed by selections)
const fields = [...t.matchAll(/^\s+(\w+)\s*[({\n]/mg)].map(m => m[1]);
const uniqueFields = [...new Set(fields)];

// Check for fragments used
const fragmentsUsed = [...t.matchAll(/\.\.\.([A-Z]\w*)/g)].map(m => m[1]);

const lines = [
  `Operation Type: ${opType}`,
  `Operation Name: ${opName}`,
  `Max Nesting:    ${maxDepth - 1} levels`,
  '',
];
if (vars.length > 0) {
  lines.push('Variables:');
  vars.forEach(v => lines.push(`  $${v.name}: ${v.type}`));
  lines.push('');
}
if (uniqueFields.length > 0) {
  lines.push('Fields referenced (heuristic):');
  lines.push('  ' + uniqueFields.slice(0, 20).join(', ') + (uniqueFields.length > 20 ? ', ...' : ''));
  lines.push('');
}
if (fragmentsUsed.length > 0) {
  lines.push('Fragments used: ' + fragmentsUsed.join(', '));
}
lines.push('Syntax: ' + (depth === 0 ? 'OK (balanced braces)' : 'WARNING: unbalanced braces'));
return { output: lines.join('\n'), outputLanguage: 'text' };
